const token = $('Get OAuth Token').item.json.access_token;
const now = new Date();
const firstOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
const firstOfNextMonth = new Date(now.getFullYear(), now.getMonth() + 1, 1);

const [salesResp, expResp, stockResp] = await Promise.all([
  $http.request({ method:'GET',
    url:'https://firestore.googleapis.com/v1/projects/chaye-cafe-pos/databases/ai-studio-11604781-3243-486c-acd1-dd3729b669bf/documents/sales?pageSize=1000',
    headers:{Authorization:'Bearer '+token} }),
  $http.request({ method:'GET',
    url:'https://firestore.googleapis.com/v1/projects/chaye-cafe-pos/databases/ai-studio-11604781-3243-486c-acd1-dd3729b669bf/documents/expenses?pageSize=500',
    headers:{Authorization:'Bearer '+token} }),
  $http.request({ method:'GET',
    url:'https://firestore.googleapis.com/v1/projects/chaye-cafe-pos/databases/ai-studio-11604781-3243-486c-acd1-dd3729b669bf/documents/stock?pageSize=500',
    headers:{Authorization:'Bearer '+token} })
]);

// Sales last month (we're now on 1st, so look at previous month)
const prevFirst = new Date(now.getFullYear(), now.getMonth() - 1, 1);
const prevLast  = new Date(now.getFullYear(), now.getMonth(), 1);

let revenue=0, profit=0, unitsSold=0;
const itemSales = {};
for (const d of (salesResp.documents||[])) {
  const f = d.fields||{};
  const ts = f.date?.timestampValue; if (!ts) continue;
  const dt = new Date(ts);
  if (dt < prevFirst || dt >= prevLast) continue;
  const p = parseFloat(f.profit?.doubleValue||f.profit?.integerValue||0);
  const u = parseFloat(f.units?.doubleValue||f.units?.integerValue||0);
  const s = parseFloat(f.sellPrice?.doubleValue||f.sellPrice?.integerValue||0);
  profit  += p; unitsSold += u; revenue += u*s;
  const name = f.itemName?.stringValue||'Other';
  itemSales[name] = (itemSales[name]||0) + u;
}

let expenses=0;
for (const d of (expResp.documents||[])) {
  const f=d.fields||{};
  const ts=f.date?.timestampValue; if(!ts) continue;
  const dt=new Date(ts);
  if(dt<prevFirst||dt>=prevLast) continue;
  expenses += parseFloat(f.amount?.doubleValue||f.amount?.integerValue||0);
}

const netProfit = profit - expenses;
const topItems = Object.entries(itemSales).sort((a,b)=>b[1]-a[1]).slice(0,5);
const topList  = topItems.map(([n,u]) => `  🏆 ${n}: ${u} units`).join('\n');

const monthName = prevFirst.toLocaleDateString('ur-PK',{month:'long',year:'numeric'});
const emoji = netProfit>=0 ? '✅' : '❌';

const msg = `📊 <b>CHAYE CAFE — Mahana Report</b>
📅 ${monthName}

━━━━━━━━━━━━━━━
💰 Total Revenue:   Rs. ${revenue.toFixed(0)}
📦 Total Units Sold: ${unitsSold}
📈 Gross Profit:     Rs. ${profit.toFixed(0)}
💸 Total Expenses:   Rs. ${expenses.toFixed(0)}
${emoji} Net Profit:      <b>Rs. ${netProfit.toFixed(0)}</b>
━━━━━━━━━━━━━━━

🥇 Top 5 Best Sellers:
${topList||'  (No data)'}

${netProfit>=0?'🎉 Acha mahana raha! Keep it up!':'⚠️ Is mahane loss hua. Expenses dekhein!'}`;

return [{json:{message:msg}}];
